import{_ as l,o as n,c as e,a4 as o,j as t,a as r}from"./chunks/framework.ChErgFjV.js";const p=JSON.parse('{"title":"初一数学知识体系","description":"","frontmatter":{"title":"初一数学知识体系","date":"2026-07-03T00:00:00.000Z","tags":["初中数学","七年级","广州中考"]},"headers":[],"relativePath":"study/junior-math/grade7.md","filePath":"study/junior-math/grade7.md","lastUpdated":null}'),s={name:"study/junior-math/grade7.md"};function i(d,a,h,g,u,c){return n(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="初一数学知识体系-七年级" tabindex="-1">初一数学知识体系（七年级） <a class="header-anchor" href="#初一数学知识体系-七年级" aria-label="Permalink to &quot;初一数学知识体系（七年级）&quot;">​</a></h1><blockquote><p>🔴 <strong>中考高频</strong>　🟡 <strong>中考常考</strong>　🟢 <strong>基础掌握</strong></p><p>基于人教版教材，结合 2022—2025 年广州中考命题规律标注重点。</p></blockquote><hr><h2 id="七年级上册" tabindex="-1">七年级上册 <a class="header-anchor" href="#七年级上册" aria-label="Permalink to &quot;七年级上册&quot;">​</a></h2><h3 id="第一章-有理数-🟡" tabindex="-1">第一章 有理数 🟡 <a class="header-anchor" href="#第一章-有理数-🟡" aria-label="Permalink to &quot;第一章 有理数 🟡&quot;">​</a></h3><h4 id="_1-1-正数和负数" tabindex="-1">1.1 正数和负数 <a class="header-anchor" href="#_1-1-正数和负数" aria-label="Permalink to &quot;1.1 正数和负数&quot;">​</a></h4><p><strong>知识点</strong>：正数、负数的概念；用正负数表示具有相反意义的量。</p><p><strong>案例</strong>：</p><ul><li>若零上 8°C 记作 +8°C，则零下 5°C 记作 <strong>-5°C</strong></li><li>向东走 50 米记作 +50 米，则向西走 30 米记作 <strong>-30 米</strong></li></ul><h4 id="_1-2-有理数" tabindex="-1">1.2 有理数 <a class="header-anchor" href="#_1-2-有理数" aria-label="Permalink to &quot;1.2 有理数&quot;">​</a></h4><p><strong>知识点</strong>：有理数的分类（整数 + 分数）；数轴、相反数、绝对值。</p><p><strong>案例</strong>：</p><ul><li>|-3| = <strong>3</strong>，|0| = <strong>0</strong>，|+5| = <strong>5</strong></li><li>-3 的相反数是 <strong>3</strong>，0 的相反数是 <strong>0</strong></li><li>在数轴上，右边的数总比左边的数大</li></ul><h4 id="_1-3-有理数的加减法-🟡" tabindex="-1">1.3 有理数的加减法 🟡 <a class="header-anchor" href="#_1-3-有理数的加减法-🟡" aria-label="Permalink to &quot;1.3 有理数的加减法 🟡&quot;">​</a></h4><p><strong>知识点</strong>：有理数加法法则、减法法则；加减混合运算。</p><p><strong>案例</strong>：</p><ul><li>(-3) + (+5) = <strong>2</strong></li><li>(-8) - (-3) = (-8) + (+3) = <strong>-5</strong></li><li>某天最低温 -5°C，最高温 6°C，温差 = 6 - (-5) = <strong>11°C</strong></li></ul><h4 id="_1-4-有理数的乘除法-🟡" tabindex="-1">1.4 有理数的乘除法 🟡 <a class="header-anchor" href="#_1-4-有理数的乘除法-🟡" aria-label="Permalink to &quot;1.4 有理数的乘除法 🟡&quot;">​</a></h4><p><strong>知识点</strong>：乘法法则（同号得正、异号得负）；除法转化乘法；乘方运算。</p><p><strong>案例</strong>：</p><ul><li>(-2) × (-3) = <strong>6</strong></li><li>(-12) ÷ (+4) = <strong>-3</strong></li><li>(-2)³ = <strong>-8</strong>，(-3)² = <strong>9</strong>，-3² = <strong>-9</strong>（注意区分）</li></ul><blockquote><p>⚠️ <strong>易错点</strong>：<code>(-3)² = 9</code> 与 <code>-3² = -9</code> 是中考常考陷阱。</p></blockquote><h4 id="_1-5-有理数的混合运算-🟡" tabindex="-1">1.5 有理数的混合运算 🟡 <a class="header-anchor" href="#_1-5-有理数的混合运算-🟡" aria-label="Permalink to &quot;1.5 有理数的混合运算 🟡&quot;">​</a></h4><p><strong>知识点</strong>：运算顺序（先乘方、再乘除、后加减）；科学记数法。</p><p><strong>案例</strong>：</p><ul><li>-1⁴ - (-1)⁴ = -1 - 1 = <strong>-2</strong></li><li>科学记数法：567000 = <strong>5.67 × 10⁵</strong></li></ul><hr><h3 id="第二章-整式的加减-🟢" tabindex="-1">第二章 整式的加减 🟢 <a class="header-anchor" href="#第二章-整式的加减-🟢" aria-label="Permalink to &quot;第二章 整式的加减 🟢&quot;">​</a></h3><h4 id="_2-1-整式" tabindex="-1">2.1 整式 <a class="header-anchor" href="#_2-1-整式" aria-label="Permalink to &quot;2.1 整式&quot;">​</a></h4><p><strong>知识点</strong>：单项式（系数、次数）、多项式（项、次数、常数项）。</p><p><strong>案例</strong>：</p><ul><li>3x²y 的系数是 <strong>3</strong>，次数是 <strong>3</strong></li><li>2x³ - 5x + 3 是三次三项式，常数项为 <strong>3</strong></li></ul><h4 id="_2-2-整式的加减" tabindex="-1">2.2 整式的加减 <a class="header-anchor" href="#_2-2-整式的加减" aria-label="Permalink to &quot;2.2 整式的加减&quot;">​</a></h4><p><strong>知识点</strong>：合并同类项；去括号法则。</p><p><strong>案例</strong>：</p><ul><li>3x² + 2x - x² + 5x = (3-1)x² + (2+5)x = <strong>2x² + 7x</strong></li><li>2(x - 3) - 3(2x + 1) = 2x - 6 - 6x - 3 = <strong>-4x - 9</strong></li></ul><hr><h3 id="第三章-一元一次方程-🔴" tabindex="-1">第三章 一元一次方程 🔴 <a class="header-anchor" href="#第三章-一元一次方程-🔴" aria-label="Permalink to &quot;第三章 一元一次方程 🔴&quot;">​</a></h3><blockquote><p>🔴 <strong>中考高频</strong>：方程是初中数学核心，每年必考，常出现在选择题和应用题中。</p></blockquote><h4 id="_3-1-从算式到方程" tabindex="-1">3.1 从算式到方程 <a class="header-anchor" href="#_3-1-从算式到方程" aria-label="Permalink to &quot;3.1 从算式到方程&quot;">​</a></h4><p><strong>知识点</strong>：方程的概念；等式的性质。</p><p><strong>案例</strong>：</p><ul><li>等式性质 1：若 a = b，则 a + c = b + c</li><li>等式性质 2：若 a = b，则 ac = bc（c ≠ 0）</li></ul><h4 id="_3-2-解一元一次方程-一-——合并同类项与移项-🟡" tabindex="-1">3.2 解一元一次方程（一）——合并同类项与移项 🟡 <a class="header-anchor" href="#_3-2-解一元一次方程-一-——合并同类项与移项-🟡" aria-label="Permalink to &quot;3.2 解一元一次方程（一）——合并同类项与移项 🟡&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>解方程：3x + 5 = 2x - 1 <ul><li>移项：3x - 2x = -1 - 5</li><li>合并：x = <strong>-6</strong></li></ul></li></ul><h4 id="_3-3-解一元一次方程-二-——去括号与去分母-🔴" tabindex="-1">3.3 解一元一次方程（二）——去括号与去分母 🔴 <a class="header-anchor" href="#_3-3-解一元一次方程-二-——去括号与去分母-🔴" aria-label="Permalink to &quot;3.3 解一元一次方程（二）——去括号与去分母 🔴&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>解方程：(2x + 1)/3 - (x - 1)/2 = 1 <ul><li>去分母（乘 6）：2(2x + 1) - 3(x - 1) = 6</li><li>去括号：4x + 2 - 3x + 3 = 6</li><li>合并：x + 5 = 6 → x = <strong>1</strong></li></ul></li></ul><blockquote><p>⚠️ <strong>中考重点</strong>：去分母时不要漏乘不含分母的项。</p></blockquote><h4 id="_3-4-实际问题与一元一次方程-🔴" tabindex="-1">3.4 实际问题与一元一次方程 🔴 <a class="header-anchor" href="#_3-4-实际问题与一元一次方程-🔴" aria-label="Permalink to &quot;3.4 实际问题与一元一次方程 🔴&quot;">​</a></h4><blockquote><p>🔴 <strong>必考</strong>：应用题是方程的考查核心，常见类型：</p></blockquote><table tabindex="0"><thead><tr><th>题型</th><th>关键等量关系</th></tr></thead><tbody><tr><td>行程问题</td><td>路程 = 速度 × 时间</td></tr><tr><td>工程问题</td><td>工作量 = 工作效率 × 工作时间</td></tr><tr><td>利润问题</td><td>利润率 = 利润/成本 × 100%</td></tr><tr><td>积分问题</td><td>胜场积分 + 平场积分 + 负场积分 = 总积分</td></tr></tbody></table><p><strong>案例</strong>：</p><ul><li>某商品进价 200 元，标价 360 元，打折后仍获利 20%，求打几折？ <ul><li>设打 x 折：360 × x/10 = 200 × (1 + 20%)</li><li>36x = 240 → x = <strong>6.67 折</strong></li></ul></li></ul><hr><h3 id="第四章-几何图形初步-🟢" tabindex="-1">第四章 几何图形初步 🟢 <a class="header-anchor" href="#第四章-几何图形初步-🟢" aria-label="Permalink to &quot;第四章 几何图形初步 🟢&quot;">​</a></h3><h4 id="_4-1-几何图形" tabindex="-1">4.1 几何图形 <a class="header-anchor" href="#_4-1-几何图形" aria-label="Permalink to &quot;4.1 几何图形&quot;">​</a></h4><p><strong>知识点</strong>：立体图形与平面图形；展开图。</p><h4 id="_4-2-直线、射线、线段" tabindex="-1">4.2 直线、射线、线段 <a class="header-anchor" href="#_4-2-直线、射线、线段" aria-label="Permalink to &quot;4.2 直线、射线、线段&quot;">​</a></h4><p><strong>知识点</strong>：两点确定一条直线；两点之间线段最短。</p><p><strong>案例</strong>：</p><ul><li>已知线段 AB = 10cm，M 是 AB 中点，N 是 MB 中点，则 MN = <strong>2.5cm</strong></li></ul><h4 id="_4-3-角-🟡" tabindex="-1">4.3 角 🟡 <a class="header-anchor" href="#_4-3-角-🟡" aria-label="Permalink to &quot;4.3 角 🟡&quot;">​</a></h4><p><strong>知识点</strong>：角的度量；角平分线；余角和补角。</p><p><strong>案例</strong>：</p><ul><li>∠α = 35°，则余角 = <strong>55°</strong>，补角 = <strong>145°</strong></li><li>一个角的补角比它的余角的 3 倍少 10°，求这个角 <ul><li>设角为 x°，则 (180-x) = 3(90-x) - 10</li><li>180 - x = 270 - 3x - 10 → 2x = 80 → x = <strong>40°</strong></li></ul></li></ul><hr><h2 id="七年级下册" tabindex="-1">七年级下册 <a class="header-anchor" href="#七年级下册" aria-label="Permalink to &quot;七年级下册&quot;">​</a></h2><h3 id="第五章-相交线与平行线-🟡" tabindex="-1">第五章 相交线与平行线 🟡 <a class="header-anchor" href="#第五章-相交线与平行线-🟡" aria-label="Permalink to &quot;第五章 相交线与平行线 🟡&quot;">​</a></h3><h4 id="_5-1-相交线-🟡" tabindex="-1">5.1 相交线 🟡 <a class="header-anchor" href="#_5-1-相交线-🟡" aria-label="Permalink to &quot;5.1 相交线 🟡&quot;">​</a></h4><p><strong>知识点</strong>：对顶角相等；邻补角互补；垂线（最短距离）。</p><p><strong>案例</strong>：</p><ul><li>两条直线相交，∠1 = 70°，则对顶角 ∠3 = <strong>70°</strong>，邻补角 ∠2 = <strong>110°</strong></li></ul><h4 id="_5-2-平行线及其判定-🔴" tabindex="-1">5.2 平行线及其判定 🔴 <a class="header-anchor" href="#_5-2-平行线及其判定-🔴" aria-label="Permalink to &quot;5.2 平行线及其判定 🔴&quot;">​</a></h4><blockquote><p>🔴 <strong>中考高频</strong>：平行线性质与判定是几何证明的基础，中考必考。</p></blockquote><p><strong>知识点</strong>：同位角相等 → 两直线平行；内错角相等 → 两直线平行；同旁内角互补 → 两直线平行。</p><p><strong>案例</strong>：</p><ul><li>已知 ∠1 = ∠2，判断 AB∥CD 的依据是 <strong>同位角相等，两直线平行</strong></li></ul><h4 id="_5-3-平行线的性质-🔴" tabindex="-1">5.3 平行线的性质 🔴 <a class="header-anchor" href="#_5-3-平行线的性质-🔴" aria-label="Permalink to &quot;5.3 平行线的性质 🔴&quot;">​</a></h4><p><strong>知识点</strong>：两直线平行 → 同位角相等；内错角相等；同旁内角互补。</p><p><strong>案例</strong>：</p><ul><li>AB∥CD，∠1 = 65°，则内错角 ∠2 = <strong>65°</strong>，同旁内角 ∠3 = <strong>115°</strong></li></ul><blockquote><p>⚠️ <strong>中考规律</strong>：广州中考常将平行线与三角形内角和结合出综合题。</p></blockquote><h4 id="_5-4-平移" tabindex="-1">5.4 平移 <a class="header-anchor" href="#_5-4-平移" aria-label="Permalink to &quot;5.4 平移&quot;">​</a></h4><p><strong>知识点</strong>：平移的性质（对应点连线平行且相等）；平移作图。</p><hr><h3 id="第六章-实数-🟡" tabindex="-1">第六章 实数 🟡 <a class="header-anchor" href="#第六章-实数-🟡" aria-label="Permalink to &quot;第六章 实数 🟡&quot;">​</a></h3><h4 id="_6-1-平方根-🟡" tabindex="-1">6.1 平方根 🟡 <a class="header-anchor" href="#_6-1-平方根-🟡" aria-label="Permalink to &quot;6.1 平方根 🟡&quot;">​</a></h4><p><strong>知识点</strong>：算术平方根、平方根的概念与表示。</p><p><strong>案例</strong>：</p><ul><li>√9 = <strong>3</strong>（算术平方根），9 的平方根 = <strong>±3</strong></li><li>√(-3)² = √9 = <strong>3</strong></li></ul><h4 id="_6-2-立方根-🟢" tabindex="-1">6.2 立方根 🟢 <a class="header-anchor" href="#_6-2-立方根-🟢" aria-label="Permalink to &quot;6.2 立方根 🟢&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>³√8 = <strong>2</strong>，³√(-27) = <strong>-3</strong></li></ul><h4 id="_6-3-实数-🟡" tabindex="-1">6.3 实数 🟡 <a class="header-anchor" href="#_6-3-实数-🟡" aria-label="Permalink to &quot;6.3 实数 🟡&quot;">​</a></h4><p><strong>知识点</strong>：无理数的概念；实数的分类；实数与数轴的一一对应。</p><p><strong>案例</strong>：</p><ul><li>下列是无理数的是：√2、π、0.1010010001...（每两个 1 之间 0 的个数递增）</li><li>|√2 - 1| + |√2 - 2| = (√2 - 1) + (2 - √2) = <strong>1</strong></li></ul><hr><h3 id="第七章-平面直角坐标系-🟡" tabindex="-1">第七章 平面直角坐标系 🟡 <a class="header-anchor" href="#第七章-平面直角坐标系-🟡" aria-label="Permalink to &quot;第七章 平面直角坐标系 🟡&quot;">​</a></h3><h4 id="_7-1-有序数对" tabindex="-1">7.1 有序数对 <a class="header-anchor" href="#_7-1-有序数对" aria-label="Permalink to &quot;7.1 有序数对&quot;">​</a></h4><h4 id="_7-2-平面直角坐标系-🟡" tabindex="-1">7.2 平面直角坐标系 🟡 <a class="header-anchor" href="#_7-2-平面直角坐标系-🟡" aria-label="Permalink to &quot;7.2 平面直角坐标系 🟡&quot;">​</a></h4><p><strong>知识点</strong>：各象限点的坐标特征；关于坐标轴和原点对称的点。</p><p><strong>案例</strong>：</p><table tabindex="0"><thead><tr><th>位置</th><th>坐标特征</th></tr></thead><tbody><tr><td>第一象限</td><td>(+, +)</td></tr><tr><td>第二象限</td><td>(-, +)</td></tr><tr><td>第三象限</td><td>(-, -)</td></tr><tr><td>第四象限</td><td>(+, -)</td></tr><tr><td>x 轴上</td><td>(x, 0)</td></tr><tr><td>y 轴上</td><td>(0, y)</td></tr></tbody></table><ul><li>点 P(3, -2) 关于 x 轴对称 → <strong>(3, 2)</strong>，关于 y 轴对称 → <strong>(-3, -2)</strong>，关于原点对称 → <strong>(-3, 2)</strong></li></ul><h4 id="_7-3-坐标系中的图形平移-🟡" tabindex="-1">7.3 坐标系中的图形平移 🟡 <a class="header-anchor" href="#_7-3-坐标系中的图形平移-🟡" aria-label="Permalink to &quot;7.3 坐标系中的图形平移 🟡&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>点 A(2, 3) 向右平移 3 个单位，再向下平移 2 个单位 → <strong>(5, 1)</strong></li></ul><blockquote><p>💡 <strong>中考提示</strong>：坐标系常与函数图像、几何变换结合出题。</p></blockquote><hr><h3 id="第八章-二元一次方程组-🟡" tabindex="-1">第八章 二元一次方程组 🟡 <a class="header-anchor" href="#第八章-二元一次方程组-🟡" aria-label="Permalink to &quot;第八章 二元一次方程组 🟡&quot;">​</a></h3><h4 id="_8-1-二元一次方程组" tabindex="-1">8.1 二元一次方程组 <a class="header-anchor" href="#_8-1-二元一次方程组" aria-label="Permalink to &quot;8.1 二元一次方程组&quot;">​</a></h4><h4 id="_8-2-消元——解二元一次方程组-🔴" tabindex="-1">8.2 消元——解二元一次方程组 🔴 <a class="header-anchor" href="#_8-2-消元——解二元一次方程组-🔴" aria-label="Permalink to &quot;8.2 消元——解二元一次方程组 🔴&quot;">​</a></h4><p><strong>知识点</strong>：代入消元法、加减消元法。</p><p><strong>案例</strong>：</p>',117),t("ul",null,[t("li",{"2x":"","+":"",y:"","css-module":"5.①，3x 4.②","-":"","2y":""},[r("解方程组： "),t("ul",null,[t("li",null,"① × 2：4x + 2y = 10 ...③"),t("li",null,[r("③ + ②：7x = 14 → x = "),t("strong",null,"2")]),t("li",null,[r("代入①：4 + y = 5 → y = "),t("strong",null,"1")])])])],-1),o('<h4 id="_8-3-实际问题与二元一次方程组-🟡" tabindex="-1">8.3 实际问题与二元一次方程组 🟡 <a class="header-anchor" href="#_8-3-实际问题与二元一次方程组-🟡" aria-label="Permalink to &quot;8.3 实际问题与二元一次方程组 🟡&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>鸡兔同笼：鸡兔共 35 只，脚共 94 只，各几只？ <ul><li>{ x + y = 35，2x + 4y = 94 } → 鸡 <strong>23</strong> 只，兔 <strong>12</strong> 只</li></ul></li></ul><hr><h3 id="第九章-不等式与不等式组-🔴" tabindex="-1">第九章 不等式与不等式组 🔴 <a class="header-anchor" href="#第九章-不等式与不等式组-🔴" aria-label="Permalink to &quot;第九章 不等式与不等式组 🔴&quot;">​</a></h3><blockquote><p>🔴 <strong>中考高频</strong>：不等式是广州中考重点，常与方案设计、最值问题结合。</p></blockquote><h4 id="_9-1-不等式" tabindex="-1">9.1 不等式 <a class="header-anchor" href="#_9-1-不等式" aria-label="Permalink to &quot;9.1 不等式&quot;">​</a></h4><p><strong>知识点</strong>：不等式的基本性质（特别注意：两边同乘负数，不等号方向改变）。</p><p><strong>案例</strong>：</p><ul><li>若 a &gt; b，则 -2a <strong>&lt;</strong> -2b</li></ul><h4 id="_9-2-一元一次不等式-🟡" tabindex="-1">9.2 一元一次不等式 🟡 <a class="header-anchor" href="#_9-2-一元一次不等式-🟡" aria-label="Permalink to &quot;9.2 一元一次不等式 🟡&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>解不等式：2(x - 1) ≤ 3x + 1 <ul><li>2x - 2 ≤ 3x + 1 → -x ≤ 3 → x ≥ <strong>-3</strong></li></ul></li></ul><h4 id="_9-3-一元一次不等式组-🔴" tabindex="-1">9.3 一元一次不等式组 🔴 <a class="header-anchor" href="#_9-3-一元一次不等式组-🔴" aria-label="Permalink to &quot;9.3 一元一次不等式组 🔴&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>解不等式组：{ 2x + 1 &gt; 0 ...①，3x - 2 ≤ 7 ...② } <ul><li>由①：x &gt; -1/2；由②：x ≤ 3</li><li>解集：<strong>-1/2 &lt; x ≤ 3</strong></li></ul></li></ul><blockquote><p>⚠️ <strong>口诀</strong>：同大取大，同小取小，大小小大取中间，大大小小无解。</p></blockquote><h4 id="_9-4-实际问题与一元一次不等式-🔴" tabindex="-1">9.4 实际问题与一元一次不等式 🔴 <a class="header-anchor" href="#_9-4-实际问题与一元一次不等式-🔴" aria-label="Permalink to &quot;9.4 实际问题与一元一次不等式 🔴&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>某商店购进单价 40 元的商品，标价 60 元，打折销售要保证利润率不低于 5%，最多打几折？ <ul><li>60 × x/10 ≥ 40 × (1 + 5%) → 6x ≥ 42 → x ≥ 7</li><li>至少打 <strong>7 折</strong></li></ul></li></ul><hr><h3 id="第十章-数据的收集、整理与描述-🟢" tabindex="-1">第十章 数据的收集、整理与描述 🟢 <a class="header-anchor" href="#第十章-数据的收集、整理与描述-🟢" aria-label="Permalink to &quot;第十章 数据的收集、整理与描述 🟢&quot;">​</a></h3><h4 id="_10-1-统计调查" tabindex="-1">10.1 统计调查 <a class="header-anchor" href="#_10-1-统计调查" aria-label="Permalink to &quot;10.1 统计调查&quot;">​</a></h4><p><strong>知识点</strong>：全面调查与抽样调查；总体、个体、样本、样本容量。</p><h4 id="_10-2-直方图" tabindex="-1">10.2 直方图 <a class="header-anchor" href="#_10-2-直方图" aria-label="Permalink to &quot;10.2 直方图&quot;">​</a></h4><p><strong>知识点</strong>：频数分布直方图的绘制与读图。</p><h4 id="_10-3-课题学习" tabindex="-1">10.3 课题学习 <a class="header-anchor" href="#_10-3-课题学习" aria-label="Permalink to &quot;10.3 课题学习&quot;">​</a></h4><blockquote><p>💡 <strong>中考提示</strong>：统计部分在初一以基础概念为主，初三会进一步深化（方差、频率等）。</p></blockquote><hr><h2 id="初一重点总结" tabindex="-1">初一重点总结 <a class="header-anchor" href="#初一重点总结" aria-label="Permalink to &quot;初一重点总结&quot;">​</a></h2><h3 id="广州中考初一相关考点权重" tabindex="-1">广州中考初一相关考点权重 <a class="header-anchor" href="#广州中考初一相关考点权重" aria-label="Permalink to &quot;广州中考初一相关考点权重&quot;">​</a></h3><table tabindex="0"><thead><tr><th>章节</th><th>中考占比</th><th>重要性</th><th>说明</th></tr></thead><tbody><tr><td>一元一次方程</td><td>约 8-10%</td><td>🔴 高</td><td>应用题必考</td></tr><tr><td>不等式与不等式组</td><td>约 6-8%</td><td>🔴 高</td><td>方案设计题常考</td></tr><tr><td>平行线</td><td>约 5-7%</td><td>🟡 中高</td><td>几何证明基础</td></tr><tr><td>有理数运算</td><td>约 4-5%</td><td>🟡 中</td><td>选择填空必出</td></tr><tr><td>实数</td><td>约 3-4%</td><td>🟡 中</td><td>常与二次根式结合</td></tr><tr><td>二元一次方程组</td><td>约 3-4%</td><td>🟡 中</td><td>应用题偶尔出现</td></tr><tr><td>坐标系</td><td>约 2-3%</td><td>🟡 中</td><td>与函数图像结合</td></tr><tr><td>整式加减</td><td>约 2%</td><td>🟢 低</td><td>基础运算</td></tr><tr><td>几何初步</td><td>约 2%</td><td>🟢 低</td><td>角度计算偶出</td></tr><tr><td>数据统计</td><td>约 2%</td><td>🟢 低</td><td>基础概念</td></tr></tbody></table><h3 id="初一学习建议" tabindex="-1">初一学习建议 <a class="header-anchor" href="#初一学习建议" aria-label="Permalink to &quot;初一学习建议&quot;">​</a></h3><ol><li><strong>有理数运算是根基</strong> — 计算能力直接影响所有后续章节</li><li><strong>方程思想要贯穿始终</strong> — 从算术思维过渡到方程思维是初一最大转折</li><li><strong>不等式易错点多</strong> — 变号问题是考试常设陷阱</li><li><strong>平行线是几何入门</strong> — 掌握&quot;判定&quot;和&quot;性质&quot;的区别，为初二三角形打基础</li></ol>',34)])])}const q=l(s,[["render",i]]);export{p as __pageData,q as default};
